export default function ProfileDocsTab({ shipment }) {
  const details = shipment.exporterDetails;

  return (
    <div>
      <h3 className="text-white font-semibold mb-4">đź“‹ Exporter Profile & Documents</h3>

      {/* Exporter Details */}
      <div className="grid grid-cols-2 gap-4 mb-6">
        {[
          { label: "Name", value: details?.name || shipment.exporterName || "â€”" },
          { label: "Email", value: shipment.exporterEmail },
          { label: "Company", value: details?.company || "â€”" },
          { label: "Phone", value: details?.phone || "â€”" },
          { label: "Address", value: details?.address || "â€”" },
          { label: "Submitted At", value: details?.submittedAt ? new Date(details.submittedAt).toLocaleString("en-IN") : "â€”" },
        ].map((item) => (
          <div key={item.label} className="bg-slate-800/50 rounded-xl p-3">
            <p className="text-xs text-slate-500 mb-1">{item.label}</p>
            <p className="text-sm text-white">{item.value}</p>
          </div>
        ))}
      </div>

      {/* Documents */}
      <h4 className="text-slate-300 font-medium mb-3">Uploaded Documents</h4>
      {shipment.documents?.length === 0 ? (
        <p className="text-slate-500 text-sm">No documents uploaded yet</p>
      ) : (
        <div className="space-y-2">
          {shipment.documents?.map((doc, i) => (
            <div key={i} className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-xl">
              <span className="text-xl">đź“„</span>
              <div className="flex-1">
                <p className="text-sm text-white">{doc.originalName || doc.name}</p>
                <p className="text-xs text-slate-500">{doc.type} â€˘ {new Date(doc.uploadedAt).toLocaleDateString("en-IN")}</p>
              </div>
              <a
                href={`${process.env.REACT_APP_API_URL?.replace("/api", "") || "http://localhost:5003"}/uploads/${doc.name}`}
                target="_blank"
                rel="noreferrer"
                className="text-xs text-blue-400 hover:text-blue-300"
              >
                View â†’
              </a>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
